test("owner can save and review a private tagged link without exposing it on public routes", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;
  const title = `Reference link ${uniqueId}`;
  const summary = `Summary for saved link ${uniqueId}`;
  const url = `https://example.com/reference-${uniqueId}`;

  await page.goto("/login");
  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "Links" }).click();

  await expect(page).toHaveURL(/\/app\/links$/);
  await page.getByRole("textbox", { name: /^URL$/ }).fill(url);
  await page.getByRole("textbox", { name: /^Title$/ }).fill(title);
  await page.getByRole("textbox", { name: /^Summary$/ }).fill(summary);
  await page.getByRole("textbox", { name: /^Tags$/ }).fill("research, reading");
  await page.getByRole("button", { name: "Save link" }).click();

  await expect(page).toHaveURL(/\/app\/links\?saved=1$/);
  await expect(page.getByText("Link saved.")).toBeVisible();
  await expect(page.getByRole("link", { name: title })).toHaveAttribute("href", url);
  await expect(page.getByText(summary)).toBeVisible();
  await expect(page.getByText("research")).toBeVisible();
  await expect(page.getByText("reading")).toBeVisible();

  await page.goto("/");
  await expect(page.getByRole("link", { name: title })).toHaveCount(0);
  await expect(page.getByText(summary)).toHaveCount(0);
});

"use server";

import { redirect } from "next/navigation";
import { revalidatePath } from "next/cache";

import { LinkValidationError } from "@/features/links/normalize";
import { DuplicateLinkUrlError, createSavedLink } from "@/features/links/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

function getLinkInput(formData: FormData) {
  return {
    url: String(formData.get("url") ?? ""),
    title: String(formData.get("title") ?? ""),
    summary: String(formData.get("summary") ?? ""),
    tags: String(formData.get("tags") ?? "")
  };
}

export async function createLinkAction(formData: FormData) {
  const owner = await requireOwnerSession();

  try {
    await createSavedLink(owner.id, getLinkInput(formData));
  } catch (error) {
    if (error instanceof LinkValidationError) {
      redirect(`/app/links?error=${error.code}`);
    }

    if (error instanceof DuplicateLinkUrlError) {
      redirect("/app/links?error=duplicate-url");
    }

    throw error;
  }

  revalidatePath("/app/links");
  redirect("/app/links?saved=1");
}

import "server-only";

import { Prisma } from "@prisma/client";

import { normalizeLinkInput } from "@/features/links/normalize";
import { linksRepo } from "@/features/links/repo";
import type { LinkDraftInput } from "@/features/links/types";

export class DuplicateLinkUrlError extends Error {
  constructor() {
    super("duplicate-link-url");
    this.name = "DuplicateLinkUrlError";
  }
}

export async function listOwnerLinks(ownerId: string) {
  return linksRepo.listForOwner(ownerId);
}

export async function createSavedLink(ownerId: string, input: LinkDraftInput) {
  const normalizedInput = normalizeLinkInput(input);

  try {
    return await linksRepo.create(ownerId, normalizedInput);
  } catch (error) {
    if (error instanceof Prisma.PrismaClientKnownRequestError && error.code === "P2002") {
      throw new DuplicateLinkUrlError();
    }

    throw error;
  }
}

import "server-only";

import { prisma } from "@/lib/prisma";

export const linksRepo = {
  async listForOwner(ownerId: string) {
    return prisma.link.findMany({
      where: {
        ownerId
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: {
        id: true,
        url: true,
        title: true,
        summary: true,
        createdAt: true,
        updatedAt: true,
        tags: {
          orderBy: {
            name: "asc"
          },
          select: {
            id: true,
            name: true
          }
        }
      }
    });
  },
  async create(ownerId: string, data: { url: string; title: string; summary: string; tagNames: string[] }) {
    return prisma.link.create({
      data: {
        ownerId,
        url: data.url,
        title: data.title,
        summary: data.summary,
        tags: {
          connectOrCreate: data.tagNames.map((name) => ({
            where: {
              name
            },
            create: {
              name
            }
          }))
        }
      },
      select: {
        id: true,
        url: true,
        title: true,
        summary: true,
        createdAt: true,
        updatedAt: true,
        tags: {
          orderBy: {
            name: "asc"
          },
          select: {
            id: true,
            name: true
          }
        }
      }
    });
  }
};

import { createLinkAction } from "@/app/app/links/actions";
import { listOwnerLinks } from "@/features/links/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type LinksPageProps = {
  searchParams?: Promise<{
    saved?: string;
    error?: string;
  }>;
};

function getStatusMessage(error?: string) {
  switch (error) {
    case "duplicate-url":
      return "That URL is already saved in your private links.";
    case "invalid-url":
      return "Enter a complete URL, including the protocol.";
    case "missing-title":
      return "Enter a title for the saved link.";
    case "missing-summary":
      return "Enter a summary for the saved link.";
    default:
      return undefined;
  }
}

export default async function LinksPage({ searchParams }: LinksPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const links = await listOwnerLinks(owner.id);
  const statusMessage =
    resolvedSearchParams.saved === "1" ? "Link saved." : getStatusMessage(resolvedSearchParams.error);

  return (
    <div className="feature-layout">
      <section className="feature-card">
        <p className="eyebrow">Private links</p>
        <h1>Save links for later retrieval.</h1>
        <p className="lede">
          Manual bookmark capture stays private in v1. Each saved link keeps its URL, title, summary, and shared tags
          inside the owner area only.
        </p>
        {statusMessage ? (
          <p className={resolvedSearchParams.error ? "status-note status-note-error" : "status-note"}>{statusMessage}</p>
        ) : null}
      </section>

      <div className="link-manager-grid">
        <form action={createLinkAction} className="panel-card link-form">
          <strong>Capture a link</strong>
          <label className="field-group">
            <span>URL</span>
            <input
              autoComplete="url"
              className="text-input"
              name="url"
              placeholder="https://example.com/article"
              required
              type="url"
            />
          </label>
          <label className="field-group">
            <span>Title</span>
            <input
              autoComplete="off"
              className="text-input"
              name="title"
              placeholder="Reference title"
              required
              type="text"
            />
          </label>
          <label className="field-group">
            <span>Summary</span>
            <textarea
              className="note-textarea summary-textarea"
              name="summary"
              placeholder="Why this link matters and what you expect to find there later."
              required
            />
          </label>
          <label className="field-group">
            <span>Tags</span>
            <input
              autoComplete="off"
              className="text-input"
              name="tags"
              placeholder="research, reference"
              type="text"
            />
          </label>
          <p className="field-note">Use commas to share tags with the rest of the private vault.</p>
          <div className="button-row">
            <button className="primary-button" type="submit">
              Save link
            </button>
          </div>
        </form>

        <section className="panel-card link-list-panel">
          <strong>Saved links</strong>
          {links.length === 0 ? (
            <p>No saved links yet. Capture the first private bookmark from this page.</p>
          ) : (
            <div className="link-list">
              {links.map((link) => (
                <article className="link-list-item" key={link.id}>
                  <div className="link-list-heading">
                    <a className="note-list-link" href={link.url} rel="noreferrer" target="_blank">
                      {link.title}
                    </a>
                    <p className="link-url">{link.url}</p>
                  </div>
                  <p className="link-summary">{link.summary}</p>
                  <div className="link-list-footer">
                    <div className="tag-list" aria-label="Tags">
                      {link.tags.length === 0 ? (
                        <span className="tag-pill tag-pill-muted">Untagged</span>
                      ) : (
                        link.tags.map((tag) => (
                          <span className="tag-pill" key={tag.id}>
                            {tag.name}
                          </span>
                        ))
                      )}
                    </div>
                    <div className="note-meta">
                      <span>Private link</span>
                      <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(link.updatedAt)}</span>
                    </div>
                  </div>
                </article>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

import test from "node:test";
import assert from "node:assert/strict";

import { normalizeLinkInput, normalizeTagNames } from "../../src/features/links/normalize";

test("normalizeTagNames trims, deduplicates, and lowercases shared tags", () => {
  assert.deepEqual(normalizeTagNames(" Research, inbox\nresearch, Reading "), ["inbox", "reading", "research"]);
});

test("normalizeLinkInput trims fields and canonicalizes the URL", () => {
  assert.deepEqual(
    normalizeLinkInput({
      url: " https://example.com/path ",
      title: " Example title ",
      summary: " Helpful reference ",
      tags: "Docs, docs"
    }),
    {
      url: "https://example.com/path",
      title: "Example title",
      summary: "Helpful reference",
      tagNames: ["docs"]
    }
  );
});

